('pizza-menu-using-react', 'jones-6199/pizza-menu-using-react-', 'pizza-menu-using-react-', 'Pizza Menu application built using React.js. It displays a list of pizzas with their details using reusable components and organized state management. The design is straightforward and responsive, focusing on presenting menu items clearly and interactively. This project was created to practice core React concepts.', 'https://github.com/Jones-6199/pizza-menu-using-react-', NULL, 7, 0, 'JavaScript', '["css3","html5","javascript","reactjs"]', NULL, 0, 'Jones-6199', 'https://avatars.githubusercontent.com/u/225714054?v=4', 'User', 'pending', 'seed', 1762384313, 1762384421, strftime('%s','now'), strftime('%s','now'), strftime('%s','now')),
